/**
 * User notification preferences model.
 *
 * Controls how and when a user receives email notifications.
 * Currently email is the only channel — future channels can be added
 * by extending this model with channel-specific settings.
 */

import type { NotificationType } from './notification.js';

/**
 * Email frequency — controls batching/digest behavior.
 * - 'immediate': Send each notification as it occurs.
 * - 'daily_digest': Batch into a daily summary.
 * - 'weekly_digest': Batch into a weekly summary.
 */
export type EmailFrequency = 'immediate' | 'daily_digest' | 'weekly_digest';

/**
 * Email notification settings for a user.
 */
export interface EmailPreferences {
  /** Whether email notifications are enabled at all. */
  enabled: boolean;
  /** How frequently to deliver email notifications. */
  frequency: EmailFrequency;
  /** Notification types the user is subscribed to. Empty array means none. */
  subscribedCategories: NotificationType[];
}

/**
 * Full user notification preferences.
 */
export interface UserPreferences {
  id: string;
  userId: string;
  email: EmailPreferences;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for updating email preferences.
 */
export interface UpdateEmailPreferencesInput {
  enabled?: boolean;
  frequency?: EmailFrequency;
  subscribedCategories?: NotificationType[];
}

/**
 * All notification types a user can subscribe to.
 */
export const ALL_NOTIFICATION_CATEGORIES: NotificationType[] = [
  'order_confirmation',
  'order_status_update',
  'welcome',
  'account_updated',
];

/**
 * Default email preferences for new users.
 */
export function getDefaultEmailPreferences(): EmailPreferences {
  return {
    enabled: true,
    frequency: 'immediate',
    subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
  };
}

