/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications across multiple channels
 * (email, SMS, webhook). Each channel has independent enable/subscribe settings.
 *
 * DECISION CHANGE (Session 9): The original model assumed email-only delivery.
 * Session 8 added SMS support, which bypassed preferences entirely because the
 * model had no SMS fields. This refactor adds per-channel preference support so
 * that SMS (and webhook) notifications are gated by user preferences just like
 * email. Existing email preferences are preserved — the `email` field is
 * unchanged, and new `sms` and `webhook` fields default to enabled with all
 * categories subscribed.
 */

import type { NotificationType } from './notification.js';

/**
 * Email frequency — controls batching/digest behavior.
 * - 'immediate': Send each notification as it occurs.
 * - 'daily_digest': Batch into a daily summary.
 * - 'weekly_digest': Batch into a weekly summary.
 */
export type EmailFrequency = 'immediate' | 'daily_digest' | 'weekly_digest';

/**
 * Email notification settings for a user.
 */
export interface EmailPreferences {
  /** Whether email notifications are enabled at all. */
  enabled: boolean;
  /** How frequently to deliver email notifications. */
  frequency: EmailFrequency;
  /** Notification types the user is subscribed to. Empty array means none. */
  subscribedCategories: NotificationType[];
}

/**
 * SMS notification settings for a user.
 * SMS does not support digest/frequency — messages are always immediate.
 */
export interface SmsPreferences {
  /** Whether SMS notifications are enabled. */
  enabled: boolean;
  /** Notification types the user is subscribed to via SMS. */
  subscribedCategories: NotificationType[];
}

/**
 * Webhook notification settings for a user.
 * Webhooks are always immediate — no digest support.
 */
export interface WebhookPreferences {
  /** Whether webhook notifications are enabled. */
  enabled: boolean;
  /** Notification types the user is subscribed to via webhook. */
  subscribedCategories: NotificationType[];
}

/**
 * Full user notification preferences.
 * Each channel has independent settings. The `sms` and `webhook` fields are
 * optional for backward compatibility — when absent, defaults are used.
 */
export interface UserPreferences {
  id: string;
  userId: string;
  email: EmailPreferences;
  sms?: SmsPreferences;
  webhook?: WebhookPreferences;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for updating email preferences.
 */
export interface UpdateEmailPreferencesInput {
  enabled?: boolean;
  frequency?: EmailFrequency;
  subscribedCategories?: NotificationType[];
}

/**
 * Input for updating SMS preferences.
 */
export interface UpdateSmsPreferencesInput {
  enabled?: boolean;
  subscribedCategories?: NotificationType[];
}

/**
 * Input for updating webhook preferences.
 */
export interface UpdateWebhookPreferencesInput {
  enabled?: boolean;
  subscribedCategories?: NotificationType[];
}

/**
 * All notification types a user can subscribe to.
 */
export const ALL_NOTIFICATION_CATEGORIES: NotificationType[] = [
  'order_confirmation',
  'order_status_update',
  'welcome',
  'account_updated',
];

/**
 * Default email preferences for new users.
 */
export function getDefaultEmailPreferences(): EmailPreferences {
  return {
    enabled: true,
    frequency: 'immediate',
    subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
  };
}

/**
 * Default SMS preferences for new users.
 */
export function getDefaultSmsPreferences(): SmsPreferences {
  return {
    enabled: true,
    subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
  };
}

/**
 * Default webhook preferences for new users.
 */
export function getDefaultWebhookPreferences(): WebhookPreferences {
  return {
    enabled: true,
    subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
  };
}

