/**
 * Update SMS preferences for a user.
 */
updateSmsPreferences(userId: string, input: UpdateSmsPreferencesInput): UserPreferences {
  this.logger.info(`Updating SMS preferences for user ${userId}`);

  const prefs = this.getOrCreatePreferences(userId);
  const updatedSms = { ...(prefs.sms ?? getDefaultSmsPreferences()) };

  if (input.enabled !== undefined) {
    updatedSms.enabled = input.enabled;
  }
  if (input.subscribedCategories !== undefined) {
    updatedSms.subscribedCategories = [...input.subscribedCategories];
  }

  return this.preferencesRepository.update(prefs.id, {
    sms: updatedSms,
    updatedAt: new Date(),
  });
}

/**
 * Update webhook preferences for a user.
 */
updateWebhookPreferences(userId: string, input: UpdateWebhookPreferencesInput): UserPreferences {
  this.logger.info(`Updating webhook preferences for user ${userId}`);

  const prefs = this.getOrCreatePreferences(userId);
  const updatedWebhook = { ...(prefs.webhook ?? getDefaultWebhookPreferences()) };

  if (input.enabled !== undefined) {
    updatedWebhook.enabled = input.enabled;
  }
  if (input.subscribedCategories !== undefined) {
    updatedWebhook.subscribedCategories = [...input.subscribedCategories];
  }

  return this.preferencesRepository.update(prefs.id, {
    webhook: updatedWebhook,
    updatedAt: new Date(),
  });
}

/**
 * Check whether a notification should be sent to a user via SMS.
 * Returns true if SMS is enabled and the user is subscribed to the category.
 */
shouldSendSms(userId: string, notificationType: NotificationType): boolean {
  const prefs = this.getOrCreatePreferences(userId);
  const sms = prefs.sms ?? getDefaultSmsPreferences();

  if (!sms.enabled) {
    this.logger.info(`SMS disabled for user ${userId}, skipping ${notificationType}`);
    return false;
  }

  if (!sms.subscribedCategories.includes(notificationType)) {
    this.logger.info(`User ${userId} not subscribed to ${notificationType} via SMS, skipping`);
    return false;
  }

  return true;
}

/**
 * Check whether a notification should be sent to a user via webhook.
 * Returns true if webhook is enabled and the user is subscribed to the category.
 */
shouldSendWebhook(userId: string, notificationType: NotificationType): boolean {
  const prefs = this.getOrCreatePreferences(userId);
  const webhook = prefs.webhook ?? getDefaultWebhookPreferences();

  if (!webhook.enabled) {
    this.logger.info(`Webhook disabled for user ${userId}, skipping ${notificationType}`);
    return false;
  }

  if (!webhook.subscribedCategories.includes(notificationType)) {
    this.logger.info(`User ${userId} not subscribed to ${notificationType} via webhook, skipping`);
    return false;
