private isAllowedByPreferences(
  userId: string,
  type: NotificationType,
  channel: NotificationChannel,
): boolean {
  if (!this.preferencesService) {
    return true;
  }

  switch (channel) {
    case 'email':
      return this.preferencesService.shouldSendEmail(userId, type);
    case 'sms':
      return this.preferencesService.shouldSendSms(userId, type);
    case 'webhook':
      return this.preferencesService.shouldSendWebhook(userId, type);
    default:
      return true;
  }
}

describe('SMS preferences', () => {
  it('should create default SMS preferences for new users', () => {
    const prefs = service.getOrCreatePreferences('user-1');

    expect(prefs.sms).toBeDefined();
    expect(prefs.sms!.enabled).toBe(true);
    expect(prefs.sms!.subscribedCategories).toEqual([
      'order_confirmation',
      'order_status_update',
      'welcome',
      'account_updated',
    ]);
  });

  it('should disable SMS notifications', () => {
    service.getOrCreatePreferences('user-1');
    const updated = service.updateSmsPreferences('user-1', { enabled: false });

    expect(updated.sms!.enabled).toBe(false);
    expect(updated.sms!.subscribedCategories).toHaveLength(4);
  });

  it('should update SMS subscribed categories', () => {
    service.getOrCreatePreferences('user-1');
    const updated = service.updateSmsPreferences('user-1', {
      subscribedCategories: ['order_confirmation'],
    });

    expect(updated.sms!.subscribedCategories).toEqual(['order_confirmation']);
  });
});

describe('shouldSendSms', () => {
  it('should return true with default preferences', () => {
    expect(service.shouldSendSms('user-1', 'order_confirmation')).toBe(true);
  });

  it('should return false when SMS is disabled', () => {
    service.updateSmsPreferences('user-1', { enabled: false });

    expect(service.shouldSendSms('user-1', 'order_confirmation')).toBe(false);
  });

  it('should return false for unsubscribed category', () => {
    service.updateSmsPreferences('user-1', {
      subscribedCategories: ['welcome'],
    });

    expect(service.shouldSendSms('user-1', 'order_confirmation')).toBe(false);
    expect(service.shouldSendSms('user-1', 'welcome')).toBe(true);
  });
});

